1	export type Item = {
2	  type: string;
3	  material?: string;
4	  cursed?: boolean;
5	  enchantment?: number;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Damage = { itemType: string; amount: number };
14	export type Incident = { cause: string; damages: Damage[] };
15	export type ClaimStep = {
16	  op: "claim";
17	  policy: number;
18	  incident: Incident;
19	};
20	
21	export type Step = QuoteStep | ClaimStep;
22	
23	export type Scenario = {
24	  customer: { yearsWithMHPCO: number };
25	  steps: Step[];
26	};
27	
28	export type QuoteResult = { premium: number };
29	export type ClaimResult = { payout: number; remainingCap: number };
30	export type StepResult = QuoteResult | ClaimResult;
31	export type ScenarioResult = { results: StepResult[] };
32	
33	const PROCESSING_FEE = 5;
34	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
35	const DEDUCTIBLE = 100;
36	const CAP_MULTIPLIER = 2;
37	
38	const INSURANCE_VALUES: Record<string, number> = {
39	  sword: 1000,
40	  amulet: 600,
41	  staff: 800,
42	  potion: 400,
43	  rune: 250,
44	  moonstone: 250,
45	};
46	
47	const BASE_PREMIUMS: Record<string, number> = {
48	  sword: 100,
49	  amulet: 60,
50	  staff: 80,
51	  potion: 40,
52	  rune: 25,
53	  moonstone: 25,
54	};
55	
56	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
57	const BLOCK_SIZE = 3;
58	const BLOCK_BASE_PREMIUM = 60;
59	const CURSE_SURCHARGE_RATE = 0.5;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
62	const LOYALTY_THRESHOLD_YEARS = 2;
63	const LOYALTY_DISCOUNT_RATE = 0.2;
64	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
65	
66	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
67	
68	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
69	
70	const componentGroupBasePremium = (type: string, count: number): number =>
71	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
72	
73	const sumItemBasePremiums = (items: Item[]): number => {
74	  const componentCounts = new Map<string, number>();
75	  let total = 0;
76	  for (const item of items) {
77	    if (isComponent(item)) {
78	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
79	    } else {
80	      total += itemBasePremium(item);
81	    }
82	  }
83	  for (const [type, count] of componentCounts) {
84	    total += componentGroupBasePremium(type, count);
85	  }
86	  return total;
87	};
88	
89	const isHighlyEnchanted = (item: Item): boolean =>
90	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
91	
92	const itemSurcharges = (item: Item): number => {
93	  const base = itemBasePremium(item);
94	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
95	  const enchantmentSurcharge = isHighlyEnchanted(item)
96	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
97	    : 0;
98	  return curseSurcharge + enchantmentSurcharge;
99	};
100	
101	const sumItemSurcharges = (items: Item[]): number =>
102	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
103	
104	const firstInsuranceSurchargeOn = (baseTotal: number): number =>
105	  baseTotal * FIRST_INSURANCE_SURCHARGE_RATE;
106	
107	export type Customer = { yearsWithMHPCO: number };
108	
109	const isLoyal = (customer: Customer): boolean =>
110	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
111	
112	const loyaltyDiscountOn = (baseTotal: number, customer: Customer): number =>
113	  isLoyal(customer) ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
114	
115	const validateQuoteItems = (items: Item[]): void => {
116	  for (const item of items) {
117	    if (!(item.type in INSURANCE_VALUES)) {
118	      throw new Error(`unknown item type "${item.type}"`);
119	    }
120	  }
121	};
122	
123	const quoteStep = (
124	  step: QuoteStep,
125	  customer: Customer,
126	  isFollowUp: boolean,
127	): QuoteResult => {
128	  validateQuoteItems(step.items);
129	  const baseTotal = sumItemBasePremiums(step.items);
130	  const itemSurchargesTotal = sumItemSurcharges(step.items);
131	  const firstInsurance = firstInsuranceSurchargeOn(baseTotal);
132	  const loyaltyDiscount = loyaltyDiscountOn(baseTotal, customer);
133	  const followUpDiscount = isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
134	  const premium = Math.ceil(
135	    baseTotal +
136	      itemSurchargesTotal +
137	      firstInsurance -
138	      loyaltyDiscount -
139	      followUpDiscount +
140	      PROCESSING_FEE,
141	  );
142	  return { premium };
143	};
144	
145	type Policy = { items: Item[]; remainingCap: number };
146	
147	const policyInsuranceSum = (items: Item[]): number =>
148	  items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
149	
150	const createPolicy = (items: Item[]): Policy => ({
151	  items,
152	  remainingCap: policyInsuranceSum(items) * CAP_MULTIPLIER,
153	});
154	
155	const SEVERE_ENCHANTMENT_THRESHOLD = 8;
156	const SEVERE_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
157	
158	const reimbursableAmount = (damage: Damage, item: Item): number => {
159	  const enchantment = item.enchantment ?? 0;
160	  if (enchantment >= SEVERE_ENCHANTMENT_THRESHOLD) {
161	    return damage.amount * SEVERE_ENCHANTMENT_REIMBURSEMENT_RATE;
162	  }
163	  return damage.amount;
164	};
165	
166	const damagePayout = (damage: Damage, item: Item): number =>
167	  Math.max(0, reimbursableAmount(damage, item) - DEDUCTIBLE);
168	
169	const findCoveredItem = (items: Item[], itemType: string): Item =>
170	  items.find((item) => item.type === itemType)!;
171	
172	const sumDamagePayouts = (damages: Damage[], items: Item[]): number =>
173	  damages.reduce(
174	    (sum, damage) => sum + damagePayout(damage, findCoveredItem(items, damage.itemType)),
175	    0,
176	  );
177	
178	const countBy = <T>(entries: T[], keyOf: (entry: T) => string): Map<string, number> => {
179	  const counts = new Map<string, number>();
180	  for (const entry of entries) {
181	    const key = keyOf(entry);
182	    counts.set(key, (counts.get(key) ?? 0) + 1);
183	  }
184	  return counts;
185	};
186	
187	const validateClaimCoverage = (damages: Damage[], items: Item[]): void => {
188	  const insuredCounts = countBy(items, (item) => item.type);
189	  const claimedCounts = countBy(damages, (damage) => damage.itemType);
190	  for (const [type, claimed] of claimedCounts) {
191	    const insured = insuredCounts.get(type) ?? 0;
192	    if (claimed > insured) {
193	      throw new Error(
194	        `claim has ${claimed} damage(s) of type "${type}" but policy only covers ${insured}`,
195	      );
196	    }
197	  }
198	};
199	
200	const claimStep = (step: ClaimStep, policy: Policy): ClaimResult => {
201	  const { damages } = step.incident;
202	  validateClaimCoverage(damages, policy.items);
203	  const requestedPayout = sumDamagePayouts(damages, policy.items);
204	  const payout = Math.floor(Math.min(requestedPayout, policy.remainingCap));
205	  policy.remainingCap -= payout;
206	  return { payout, remainingCap: policy.remainingCap };
207	};
208	
209	export const runScenario = (scenario: Scenario): ScenarioResult => {
210	  const policies: Policy[] = [];
211	  const results: StepResult[] = scenario.steps.map((step) => {
212	    if (step.op === "claim") return claimStep(step, policies[step.policy]);
213	    const isFollowUp = policies.length > 0;
214	    policies.push(createPolicy(step.items));
215	    return quoteStep(step, scenario.customer, isFollowUp);
216	  });
217	  return { results };
218	};
